// Map each selected catalog_line (sent in the webhook body by the app) to the
// Hermes item shape, and tag it add vs edit. Field mapping is the agreed one:
//   title<-title, author<-artist, releaseDate<-release_date (YYYY-MM-DD),
//   format<-format, ean<-ean, calculationGroup<-calculation_group,
//   supplierCode<-supplier_code (populated by the extraction workflow).
// A line that already has hermes_id is an EDIT; otherwise an ADD.
const lines = $('Webhook').first().json.body?.lines ?? [];
const out = [];
for (const l of lines) {
  out.push({ json: {
    _line_id: l.id,
    _ean: l.ean ?? null,
    _hermes_id: l.hermes_id ?? null,
    _mode: l.hermes_id ? 'edit' : 'add',
    item: {
      title: l.title ?? null,
      author: l.artist ?? null,
      releaseDate: l.release_date ?? null,
      format: l.format ?? null,
      ean: l.ean ?? null,
      calculationGroup: l.calculation_group ?? null,
      supplierCode: l.supplier_code ?? null,
    },
  } });
}
return out;

// Collect all ADD lines into a single { items:[...] } batch for one POST,
// keeping a parallel meta list so we can match the response back to line ids.
const all = $input.all();
return [{ json: {
  items: all.map(i => i.json.item),
  meta: all.map(i => ({ line_id: i.json._line_id, ean: i.json._ean, hermes_id: i.json._hermes_id })),
} }];

// Match the Hermes response back to each line so we can store its hermes_id.
// TODO the 200-response shape is not yet confirmed (Swagger shows a generic
// map). Adjust `pickHermesId` once we see a real response. Until then we still
// mark the line as sent; hermes_id enrichment is best-effort.
const resp = $json;
const meta = $('Aggregate Add').first().json.meta;
function pickHermesId(r, m) {
  // Common shapes to try: array aligned by index, or a map keyed by ean/item_code.
  if (Array.isArray(r)) {
    const hit = r.find(x => x && (x.ean === m.ean || x.item_code === m.ean));
    return hit?.item_code ?? hit?.id ?? null;
  }
  if (r && typeof r === 'object') {
    const v = r[m.ean];
    if (v) return v.item_code ?? v.id ?? (typeof v === 'string' ? v : null);
  }
  return null;
}
return meta.map(m => ({ json: {
  id: m.line_id,
  hermes_id: pickHermesId(resp, m) ?? m.hermes_id ?? null,
} }));

// Collect all EDIT lines into a single { items:[...] } batch.
const all = $input.all();
return [{ json: {
  items: all.map(i => i.json.item),
  meta: all.map(i => ({ line_id: i.json._line_id, ean: i.json._ean, hermes_id: i.json._hermes_id })),
} }];

// Same best-effort id matching as the Add branch; on edit we keep the existing
// hermes_id if the response doesn't return one.
const resp = $json;
const meta = $('Aggregate Edit').first().json.meta;
function pickHermesId(r, m) {
  if (Array.isArray(r)) {
    const hit = r.find(x => x && (x.ean === m.ean || x.item_code === m.ean));
    return hit?.item_code ?? hit?.id ?? null;
  }
  if (r && typeof r === 'object') {
    const v = r[m.ean];
    if (v) return v.item_code ?? v.id ?? (typeof v === 'string' ? v : null);
  }
  return null;
}
return meta.map(m => ({ json: {
  id: m.line_id,
  hermes_id: pickHermesId(resp, m) ?? m.hermes_id ?? null,
} }));
